// n8n Code Node to Extract Henry Hub Natural Gas Futures Prices + CURRENT SPOT PRICE
// This function extracts all available contract data AND the current real-time price

const items = $input.all();
const extractedData = [];

for (const item of items) {
  const htmlContent = item.json.data;

  // ========================================
  // EXTRACT CURRENT SPOT PRICE (Real-time)
  // ========================================
  let currentSpotPrice = null;
  let currentChange = null;
  let currentChangePercent = null;
  let currentChangeDirection = null;

  // Look for the current Natural Gas spot price in the header section
  const spotPricePattern = /<tr class="[^"]*" data-hash="Natural-Gas"[^>]*>(.*?)<\/tr>/s;
  const spotMatch = htmlContent.match(spotPricePattern);

  if (spotMatch) {
    const spotRow = spotMatch[1];

    // Extract current price
    const priceMatch = spotRow.match(/<td class="value">\s*([\d.]+)\s*<i/);
    if (priceMatch) {
      currentSpotPrice = parseFloat(priceMatch[1]);
    }

    // Extract change value
    const changeMatch = spotRow.match(/<td class="change_amount">\s*([+\-][\d.]+)/);
    if (changeMatch) {
      currentChange = parseFloat(changeMatch[1]);
    }

    // Extract change percentage
    const percentMatch = spotRow.match(/<td class="change_percent">\s*([+\-][\d.]+)%/);
    if (percentMatch) {
      currentChangePercent = parseFloat(percentMatch[1]);
    }

    // Extract direction (up/down)
    const directionMatch = spotRow.match(/class="(change_up|change_down)/);
    if (directionMatch) {
      currentChangeDirection = directionMatch[1].replace('change_', '');
    }
  }

  // ========================================
  // EXTRACT FUTURES CONTRACTS DATA
  // ========================================
  const rowPattern = /<div class="info_table_row" data-symbol="([^"]+)" data-days_5='([^']*)' data-days_30='([^']*)' data-days_90='([^']*)' data-year='([^']*)' data-ytd='([^']*)'[^>]*>((?:(?!<div class="info_table_row").)*?)<\/div>/gs;

  const contracts_list = [];
  let match;

  while ((match = rowPattern.exec(htmlContent)) !== null) {
    const symbol = match[1];
    const days5Price = match[2] ? parseFloat(match[2]) : null;
    const days30Price = match[3] ? parseFloat(match[3]) : null;
    const days90Price = match[4] ? parseFloat(match[4]) : null;
    const yearPrice = match[5] ? parseFloat(match[5]) : null;
    const ytdPrice = match[6] ? parseFloat(match[6]) : null;
    const innerHtml = match[7];

    // Extract contract details
    const nameMatch = innerHtml.match(/data-name="([^"]+)"/);
    const lastPriceMatch = innerHtml.match(/<div class="info_table_cell last_price">\s*([\d.]+)/);
    const changeMatch = innerHtml.match(/<div class="info_table_cell (up|down) change">\s*([+\-][\d.]+)/);
    const openMatch = innerHtml.match(/<div class="info_table_cell open">\s*([\d.]+)/);
    const highMatch = innerHtml.match(/<div class="info_table_cell high">\s*([\d.]+)/);
    const lowMatch = innerHtml.match(/<div class="info_table_cell low">\s*([\d.]+)/);
    const dateMatch = innerHtml.match(/<div class="info_table_cell date">\s*([^<\n]+)/);

    const lastPrice = lastPriceMatch ? parseFloat(lastPriceMatch[1]) : null;
    const changeDirection = changeMatch ? changeMatch[1] : null;
    const changeValue = changeMatch ? parseFloat(changeMatch[2]) : null;

    const contractData = {
      symbol: symbol,
      contract_name: nameMatch ? nameMatch[1] : '',
      last_price: lastPrice,
      change_direction: changeDirection,
      change_value: changeValue,
      change_percent: lastPrice && changeValue ? parseFloat(((changeValue / lastPrice) * 100).toFixed(2)) : null,
      open: openMatch ? parseFloat(openMatch[1]) : null,
      high: highMatch ? parseFloat(highMatch[1]) : null,
      low: lowMatch ? parseFloat(lowMatch[1]) : null,
      date_time: dateMatch ? dateMatch[1].trim() : '',
      price_5_days_ago: days5Price,
      price_30_days_ago: days30Price,
      price_90_days_ago: days90Price,
      price_1_year_ago: yearPrice,
      price_ytd: ytdPrice
    };

    // Calculate percentage changes
    if (lastPrice) {
      if (days5Price) contractData.change_5_days_percent = parseFloat((((lastPrice - days5Price) / days5Price) * 100).toFixed(2));
      if (days30Price) contractData.change_30_days_percent = parseFloat((((lastPrice - days30Price) / days30Price) * 100).toFixed(2));
      if (days90Price) contractData.change_90_days_percent = parseFloat((((lastPrice - days90Price) / days90Price) * 100).toFixed(2));
      if (yearPrice) contractData.change_1_year_percent = parseFloat((((lastPrice - yearPrice) / yearPrice) * 100).toFixed(2));
      if (ytdPrice) contractData.change_ytd_percent = parseFloat((((lastPrice - ytdPrice) / ytdPrice) * 100).toFixed(2));
    }

    contractData.scraped_at = new Date().toISOString();
    contracts_list.push(contractData);
  }

  // ========================================
  // COMBINE SPOT PRICE + CONTRACTS
  // ========================================
  // Add spot price data as a special entry at the beginning
  if (currentSpotPrice) {
    extractedData.push({
      type: 'spot_price',
      spot_price: currentSpotPrice,
      spot_change: currentChange,
      spot_change_percent: currentChangePercent,
      spot_direction: currentChangeDirection,
      timestamp: new Date().toISOString(),
      timestamp_ist: new Date().toLocaleString('en-IN', { 
        timeZone: 'Asia/Kolkata',
        year: 'numeric',
        month: 'short',
        day: 'numeric',
        hour: '2-digit',
        minute: '2-digit',
        second: '2-digit',
        hour12: true
      })
    });
  }

  // Add all contract data
  contracts_list.forEach(contract => {
    extractedData.push({
      type: 'futures_contract',
      ...contract
    });
  });
}

return extractedData.map(data => ({ json: data }));

// Get all input data
const items = $input.all();

// Separate spot price and futures contracts
let spotData = null;
const futuresContracts = [];

items.forEach(item => {
  if (item.json.type === 'spot_price') {
    spotData = item.json;
  } else if (item.json.type === 'futures_contract') {
    futuresContracts.push(item.json);
  }
});

// Build the message
let message = `📊 <b>HENRY HUB NATURAL GAS FUTURES</b>\n`;
message += `📅 ${spotData.timestamp_ist}\n`;
message += `━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n\n`;

// Spot Price Section - TABLE FORMAT (same as futures)
const isPositive = spotData.spot_change > 0;
const indicator = isPositive ? '🟢' : '🔴';

message += `💰 <b>SPOT PRICE</b>\n\n`;
message += `<pre>`;
message += `Contract  Period      Price    Change\n`;
message += `━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n`;

// Format spot price row
const spotSymbol = `${indicator} SPOT  `.padEnd(10);
const today = new Date();
const todayStr = today.toLocaleDateString('en-GB', { day: 'numeric', month: 'short', year: '2-digit' }).replace(/ /g, ' ');
const spotPeriod = `Today`.padEnd(10);
const spotPrice = `$${spotData.spot_price.toFixed(2)}`.padStart(7);
const spotChange = `${isPositive ? '$+' : '$'}${Math.abs(spotData.spot_change).toFixed(2)}`.padStart(8);

message += `${spotSymbol}  ${spotPeriod}  ${spotPrice}  ${spotChange}\n`;
message += `</pre>\n\n`;

message += `━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n`;
message += `📈 <b>NEXT 12 MONTHS</b>\n\n`;

// Futures contracts table
message += `<pre>`;
message += `Contract  Period      Price    Change\n`;
message += `━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n`;

const monthlyContracts = futuresContracts.slice(0, 12);

monthlyContracts.forEach(contract => {
  // Extract month and year from contract name
  const nameParts = contract.contract_name.replace('Natural Gas ', '').split(' ');
  const month = nameParts[0].substring(0, 3); // First 3 letters of month
  const year = `'${nameParts[1].substring(2)}`; // Last 2 digits of year

  // Use 30-day price as current (since last_price is null)
  const currentPrice = contract.price_30_days_ago;

  // Calculate change from 1 year ago
  const changeValue = contract.price_1_year_ago ? currentPrice - contract.price_1_year_ago : 0;

  // Format the row with proper spacing
  const symbol = `🔴 ${contract.symbol.padEnd(6)}`;
  const period = `${month} ${year}`.padEnd(10);
  const price = `$${currentPrice.toFixed(2)}`.padStart(7);
  const change = `${changeValue > 0 ? '$+' : '$'}${changeValue.toFixed(2)}`.padStart(8);

  message += `${symbol}  ${period}  ${price}  ${change}\n`;
});

message += `</pre>\n\n`;

// Summary stats
const monthlyPrices = monthlyContracts.map(c => c.price_30_days_ago);
const lowestPrice = Math.min(...monthlyPrices);
const highestPrice = Math.max(...monthlyPrices);
const avgPrice = monthlyPrices.reduce((a, b) => a + b, 0) / monthlyPrices.length;

message += `📊 Range: $${lowestPrice.toFixed(2)} - $${highestPrice.toFixed(2)}\n`;
message += `📈 Avg: $${avgPrice.toFixed(2)}\n\n`;

message += `━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n`;
message += `<i>🔔 Source: Henry Hub Futures Data</i>`;

// Return the formatted message
return {
  json: {
    telegram_message: message
  }
};
